xpath.script:
(function () {
    var minQtyEl = document.getElementById('price_break_min_qty_value');
    var minQty   = minQtyEl ? (parseFloat(minQtyEl.dataset.minQty) || 0) : 0;
    var errorBox = document.getElementById('price_break_min_qty_error');
    var errorTm  = null;
    var minLabel = (minQty % 1 === 0 ? parseInt(minQty) : minQty) + ' unité(s)';

    /* Setter natif : contourne le cache Owl/React */
    function setNative(input, val) {
        try {
            var setter = Object.getOwnPropertyDescriptor(
                window.HTMLInputElement.prototype, 'value').set;
            setter.call(input, val);
        } catch (e) { input.value = val; }
        ['input','change'].forEach(function(ev) {
            input.dispatchEvent(new Event(ev, { bubbles: true }));
        });
    }

    /* ---- Page produit ---- */
    function showPageError() {
        if (!errorBox || minQty <= 0) return;
        errorBox.style.display = 'block';
        clearTimeout(errorTm);
        errorTm = setTimeout(function () { errorBox.style.display = 'none'; }, 5000);
    }

    function enforcePageMin(input) {
        if (!input || minQty <= 0) return;
        if (parseFloat(input.value) < minQty) {
            showPageError();
            setNative(input, minQty);
        }
    }

    function initPageInput(input) {
        if (!input || minQty <= 0) return;
        input.setAttribute('min', minQty);
        if (!input.value || parseFloat(input.value) < minQty) setNative(input, minQty);
        input.addEventListener('change', function () { enforcePageMin(input); });
        input.addEventListener('blur',   function () { enforcePageMin(input); });
        setInterval(function () {
            if (parseFloat(input.value) < minQty) enforcePageMin(input);
        }, 300);
    }

    /* ---- Modal (Owl dialog / Bootstrap modal) ---- */
    /* On cible tout input[type=number] dans un conteneur dialog,
       en excluant l'input de la page produit elle-même. */
    var MODAL_SEL = [
        '.modal.show input[type="number"]',
        '.modal-dialog input[type="number"]',
        '.o_dialog input[type="number"]',
        '[role="dialog"] input[type="number"]',
        'dialog input[type="number"]'
    ].join(',');

    function addModalLabel(input) {
        var cell = input.closest('td') || input.closest('.input-group') || input.parentNode;
        if (!cell || cell.querySelector('.pb-modal-lbl')) return;
        var d = document.createElement('div');
        d.className = 'pb-modal-lbl text-center text-muted mt-1';
        d.style.fontSize = '0.82em';
        d.innerHTML = 'Qté mini : ' + minLabel + '';
        cell.appendChild(d);
    }

    function showModalErr(input) {
        var cell = input.closest('td') || input.closest('.input-group') || input.parentNode;
        if (!cell || cell.querySelector('.pb-modal-err')) return;
        var d = document.createElement('div');
        d.className = 'pb-modal-err text-center text-danger mt-1';
        d.style.fontSize = '0.82em';
        d.innerHTML = 'Qté minimale : ' + minLabel + '';
        cell.appendChild(d);
        setTimeout(function () { if (d.parentNode) d.parentNode.removeChild(d); }, 4000);
    }

    if (minQty > 0) {
        setInterval(function () {
            var inputs;
            try { inputs = document.querySelectorAll(MODAL_SEL); } catch(e) { return; }
            inputs.forEach(function (inp) {
                if (inp.type !== 'number' && inp.type !== 'text') return;
                addModalLabel(inp);
                if (!inp.dataset.pbInit) {
                    inp.dataset.pbInit = '1';
                    inp.setAttribute('min', minQty);
                    inp.addEventListener('change', function () {
                        if (parseFloat(inp.value) < minQty) { showModalErr(inp); setNative(inp, minQty); }
                    });
                    inp.addEventListener('blur', function () {
                        if (parseFloat(inp.value) < minQty) { showModalErr(inp); setNative(inp, minQty); }
                    });
                }
                var v = parseFloat(inp.value);
                if (!isNaN(v) && v < minQty) setNative(inp, minQty);
            });
        }, 150);
    }

    /* ---- Tableau prix dégressifs ---- */
    document.addEventListener('DOMContentLoaded', function () {
        initPageInput(document.querySelector('input[name="add_qty"]'));

        var rows = document.querySelectorAll('.price-break-row');
        var inp  = document.querySelector('input[name="add_qty"]');
        var last = inp ? inp.value : '';

        function highlight(qty) {
            var best = null;
            rows.forEach(function (r) {
                if (qty >= parseFloat(r.dataset.qty)) best = r;
            });
            rows.forEach(function (r) { r.classList.remove('price-break-active'); });
            if (best) best.classList.add('price-break-active');
        }

        function onQtyChange() {
            if (inp && inp.value !== last) {
                last = inp.value;
                var q = parseFloat(inp.value);
                if (!isNaN(q)) highlight(q);
            }
        }

        if (inp) {
            inp.addEventListener('input',  onQtyChange);
            inp.addEventListener('change', onQtyChange);
            setInterval(onQtyChange, 200);
            document.querySelectorAll('button,.btn,.fa-plus,.fa-minus,.btn-plus,.btn-minus').forEach(function (b) {
                b.addEventListener('click', function () { setTimeout(onQtyChange, 350); });
            });
        }

        rows.forEach(function (row) {
            row.addEventListener('click', function () {
                var qty = Math.max(parseFloat(row.dataset.qty), minQty || 0);
                if (inp) {
                    setNative(inp, qty);
                    last = qty.toString();
                }
                highlight(qty);
            });
        });
    });
})();

(function () {
    function showCartWarning(msg) {
        var id = 'pb_cart_warning_toast';
        var box = document.getElementById(id);
        if (!box) {
            box = document.createElement('div');
            box.id = id;
            box.style.cssText = [
                'position:fixed','top:80px','right:20px','z-index:99999',
                'max-width:420px','padding:12px 16px','border-radius:6px',
                'background:#fff3cd','border:1px solid #ffc107',
                'color:#664d03','font-size:0.9em','box-shadow:0 2px 8px rgba(0,0,0,.15)'
            ].join(';');
            document.body.appendChild(box);
        }
        box.innerHTML = '⚠' + msg;
        box.style.display = 'block';
        clearTimeout(box._t);
        box._t = setTimeout(function () { box.style.display = 'none'; }, 6000);
    }

    /* Interception fetch (Odoo 18 utilise fetch pour les appels JSON-RPC) */
    var _fetch = window.fetch;
    window.fetch = function (url, opts) {
        var p = _fetch.apply(this, arguments);
        try {
            var u = (url && url.toString) ? url.toString() : '';
            if (u.indexOf('cart/update_json') !== -1 || u.indexOf('cart_update_json') !== -1) {
                p.then(function (resp) {
                    var clone = resp.clone();
                    clone.json().then(function (data) {
                        var w = (data && data.result && data.result.warning)
                             || (data && data.warning);
                        if (w) showCartWarning(w);
                    }).catch(function () {});
                }).catch(function () {});
            }
        } catch(e) {}
        return p;
    };

    /* Interception XMLHttpRequest (fallback) */
    var _open = XMLHttpRequest.prototype.open;
    XMLHttpRequest.prototype.open = function (method, url) {
        this._pbUrl = url || '';
        return _open.apply(this, arguments);
    };
    var _send = XMLHttpRequest.prototype.send;
    XMLHttpRequest.prototype.send = function () {
        if (this._pbUrl && (this._pbUrl.indexOf('cart/update_json') !== -1 || this._pbUrl.indexOf('cart_update_json') !== -1)) {
            var self = this;
            this.addEventListener('load', function () {
                try {
                    var data = JSON.parse(self.responseText);
                    var w = (data && data.result && data.result.warning)
                         || (data && data.warning);
                    if (w) showCartWarning(w);
                } catch(e) {}
            });
        }
        return _send.apply(this, arguments);
    };
})();
